import React from "react"
import Collapsible from 'react-collapsible'
import '../collapse.css'

class Evalulation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            results: [], stage: 0, teamInfo: {}, incompleteEval: [], createEvalResult: []
        };
    }

    createEval = (buildRequest) => {
      console.log(buildRequest)
      //this.setState({stage: 99});

      let headers = new Headers();

      headers.append('Content-Type', 'application/json');
      headers.append('Accept', 'application/json');


      var backUrl = `http://localhost:9000/medhubcreateeval`
      fetch(backUrl, {
        "method": "POST",
        headers: headers,
        body: JSON.stringify({evals: buildRequest})

      })
      .then(response => response.json())
      .then(response => {
        console.log(response);
        //this.setState({results: response})
        //this.setState({incompleteEval: response})
        //this.setState({stage: 1});
        //_forEach(response, d => console.log(d.name))
        //console.log(this.state.results)
      })
      .catch(err => {
        console.log(err);
      });



    }

    goBackFirstScreen = () => {
      this.setState({stage: 0});
      this.setState({teamInfo: {}});
    }

    nameClick = (teamInfo) => {
      this.setState({stage: 99});
      this.setState({teamInfo: teamInfo});

      let headers = new Headers();

      headers.append('Content-Type', 'application/json');
      headers.append('Accept', 'application/json');

      var userIDs = []
      userIDs.push(teamInfo.userID)

      for (let y in teamInfo.members) {
        userIDs.push(teamInfo.members[y].userID)
      }


      var backUrl = `http://localhost:9000/medhubincomplete`
      fetch(backUrl, {
        "method": "POST",
        headers: headers,
        body: JSON.stringify({userIDs: userIDs})

      })
      .then(response => response.json())
      .then(response => {
        //console.log(response);
        //this.setState({results: response})
        this.setState({incompleteEval: response})
        this.setState({stage: 1});
        //_forEach(response, d => console.log(d.name))
        //console.log(this.state.results)
      })
      .catch(err => {
        console.log(err);
      });


    }


        componentDidMount() {


          const search = this.props.location.search;
          const params = new URLSearchParams(search);
          const day = params.get('day');
          const month = params.get('month');


          //console.log(day)
          //console.log(month)

          var query = ""
          if (day != null && month != null) {
            query = "?day=" + day + "&month=" + month
          }

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            //headers.append('Access-Control-Allow-Origin', 'http://localhost:3000');
            //headers.append('Access-Control-Allow-Credentials', 'true');
            //var backUrl = `http://localhost:9000/amioncall`+query
            //var backUrl = `http://192.168.2.83:9000/amioncall`+query
            var backUrl = `http://localhost:9000/amiontest`+query

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }

          render() {


            var todayDate = "Loading ..."
            var content = []


            if (this.state.stage === 1) {
              var teamHtml = ""

              todayDate = "Date: " + this.state.teamInfo.date

              var color = "black"
              if (this.state.teamInfo.turnover) {
                color = "red"
              }

              console.log(this.state.teamInfo)


              teamHtml = <div style={{marginBottom: '10px', color: color}} ><b>{this.state.teamInfo.assignment }: <u>{this.state.teamInfo.name} * medHubID: ({this.state.teamInfo.userID})</u></b></div>

              var residentsContent = []
              for (let y in this.state.teamInfo.members) {

                var colorRes = "black"
                if (this.state.teamInfo.members[y].turnover) {
                  colorRes = "red"
                }


                residentsContent.push(<div style={{marginLeft: '10px', color: colorRes}}>- {this.state.teamInfo.members[y].name} * medHubID: ({this.state.teamInfo.members[y].userID})</div>)



                for (let k in this.state.incompleteEval) {
                  if (this.state.incompleteEval[k].userID  != 0 && this.state.incompleteEval[k].userID === this.state.teamInfo.members[y].userID && this.state.incompleteEval[k].incomplete.length > 0) {

                    var evals = []
                    for(let m in this.state.incompleteEval[k].incomplete) {
                        evals.push(<div>{this.state.incompleteEval[k].incomplete[m].eval_title} ({this.state.incompleteEval[k].incomplete[m].evaluationID} - {this.state.incompleteEval[k].incomplete[m].eval_type})<hr></hr></div>)
                    }

                    residentsContent.push(<Collapsible trigger={"Incomplete Evaluation (" + this.state.incompleteEval[k].incomplete.length + ") - " + this.state.teamInfo.members[y].name}>
                      {evals}
                  </Collapsible>)
                  }
                }
                residentsContent.push(<div>--------------------------------------------------------------------------------------------</div>)


              }


              content.push(<button onClick={(e) => this.goBackFirstScreen()} style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow"}}>Go Back</button>)
              content.push(<div>************************************************************************************************</div>)

              content.push(teamHtml)


              for (let k in this.state.incompleteEval) {
                  if (this.state.incompleteEval[k].userID === this.state.teamInfo.userID && this.state.incompleteEval[k].incomplete.length > 0) {

                    var evals = []
                    for(let m in this.state.incompleteEval[k].incomplete) {
                        evals.push(<div>{this.state.incompleteEval[k].incomplete[m].eval_title} ({this.state.incompleteEval[k].incomplete[m].evaluationID} - {this.state.incompleteEval[k].incomplete[m].eval_type})<hr></hr></div>)
                    }

                    content.push(<Collapsible trigger={"Incomplete Evaluation (" + this.state.incompleteEval[k].incomplete.length + ") - " + this.state.teamInfo.name}>
                      {evals}
                  </Collapsible>)
                  }
              }
              content.push(<div><hr></hr><hr></hr></div>)

              content.push(residentsContent)
              content.push(<div>&nbsp;</div>)

              content.push(<div>&nbsp;</div>)
              content.push(<div><hr></hr></div>)
              content.push(<div><hr></hr></div>)
              content.push(<div>Create Evaluation</div>)
              content.push(<div>******************************************************************************************</div>)

              var buildRequest = []

              if (this.state.teamInfo.turnover) {
                  for (let n in this.state.teamInfo.members) {
                      if (this.state.teamInfo.members[n].resident) {
                        if (this.state.teamInfo.userID != 0 && this.state.teamInfo.members[n].userID != 0) {
                          buildRequest.push({"evaluationID":5735,"eval_type":5,"evaluator_userID":this.state.teamInfo.userID,"programID":1350,"evaluatee_userID":this.state.teamInfo.members[n].userID,"title":this.state.teamInfo.name + " => " + this.state.teamInfo.members[n].name + " IM - UC Wards (Faculty of Resident - New)"})
                          content.push(<div>{this.state.teamInfo.name} =&gt; {this.state.teamInfo.members[n].name}  IM - UC Wards (Faculty of Resident - New) </div>)  
                        } else {
                          if (this.state.teamInfo.userID === 0) {
                            content.push(<div>{this.state.teamInfo.name} doesn't have medhub ID</div>)
                          }
                          if (this.state.teamInfo.members[n].userID === 0) {
                            content.push(<div>{this.state.teamInfo.members[n].name} doesn't have medhub ID</div>)
                          }
                        }

                      }
                      if (this.state.teamInfo.members[n].intern) {
                        if (this.state.teamInfo.userID != 0 && this.state.teamInfo.members[n].userID != 0) {
                          buildRequest.push({"evaluationID":5734,"eval_type":5,"evaluator_userID":this.state.teamInfo.userID,"programID":1350,"evaluatee_userID":this.state.teamInfo.members[n].userID,"title":this.state.teamInfo.name + " => " + this.state.teamInfo.members[n].name + " IM - UC Wards (Faculty of Intern - New)"})
                          content.push(<div>{this.state.teamInfo.name} =&gt; {this.state.teamInfo.members[n].name}  IM - UC Wards (Faculty of Intern - New) </div>)  
                        } else {
                          if (this.state.teamInfo.userID === 0) {
                            content.push(<div>{this.state.teamInfo.name} doesn't have medhub ID</div>)
                          }
                          if (this.state.teamInfo.members[n].userID === 0) {
                            content.push(<div>{this.state.teamInfo.members[n].name} doesn't have medhub ID</div>)
                          }
                        }
                      }
                      if (this.state.teamInfo.userID != 0 && this.state.teamInfo.members[n].userID != 0) {
                        buildRequest.push({"evaluationID":5819,"eval_type":2,"evaluator_userID":this.state.teamInfo.members[n].userID,"programID":1350,"evaluatee_userID":this.state.teamInfo.userID,"title":this.state.teamInfo.members[n].name + " => " + this.state.teamInfo.name + " IM - Trainee Evaluation of Faculty (2019 Respect - Residency/New)"})
                        content.push(<div>{this.state.teamInfo.members[n].name} =&gt; {this.state.teamInfo.name}  IM - Trainee Evaluation of Faculty (2019 Respect - Residency/New)</div>)  
                      }
                      content.push(<div><hr></hr></div>)  
                  }
              } else {
                  for (let n in this.state.teamInfo.members) {
                      if (this.state.teamInfo.members[n].resident && this.state.teamInfo.members[n].turnover) {
                        if (this.state.teamInfo.userID != 0 && this.state.teamInfo.members[n].userID != 0) {
                          buildRequest.push({"evaluationID":5735,"eval_type":5,"evaluator_userID":this.state.teamInfo.userID,"programID":1350,"evaluatee_userID":this.state.teamInfo.members[n].userID,"title":this.state.teamInfo.name + " => " + this.state.teamInfo.members[n].name + " IM - UC Wards (Faculty of Resident - New)"})
                          content.push(<div>{this.state.teamInfo.name} =&gt; {this.state.teamInfo.members[n].name}  IM - UC Wards (Faculty of Resident - New) </div>) 
                        } else {
                          if (this.state.teamInfo.userID === 0) {
                            content.push(<div>{this.state.teamInfo.name} doesn't have medhub ID</div>)
                          }
                          if (this.state.teamInfo.members[n].userID === 0) {
                            content.push(<div>{this.state.teamInfo.members[n].name} doesn't have medhub ID</div>)
                          }
                        }
                      }
                      if (this.state.teamInfo.members[n].intern && this.state.teamInfo.members[n].turnover) {
                        if (this.state.teamInfo.userID != 0 && this.state.teamInfo.members[n].userID != 0) {
                          buildRequest.push({"evaluationID":5734,"eval_type":5,"evaluator_userID":this.state.teamInfo.userID,"programID":1350,"evaluatee_userID":this.state.teamInfo.members[n].userID,"title":this.state.teamInfo.name + " => " + this.state.teamInfo.members[n].name + " IM - UC Wards (Faculty of Intern - New)"})
                          content.push(<div>{this.state.teamInfo.name} =&gt; {this.state.teamInfo.members[n].name}  IM - UC Wards (Faculty of Intern - New) </div>)  
                        } else {
                          if (this.state.teamInfo.userID === 0) {
                            content.push(<div>{this.state.teamInfo.name} doesn't have medhub ID</div>)
                          }
                          if (this.state.teamInfo.members[n].userID === 0) {
                            content.push(<div>{this.state.teamInfo.members[n].name} doesn't have medhub ID</div>)
                          }
                        }
                      }

                      content.push(<div><hr></hr></div>)  
                  }


              }

              if (buildRequest.length > 0) {
                content.push(<button onClick={(e) => this.createEval(buildRequest)} style={{height: "30px", width: "200px", fontSize: "16px", backgroundColor: "yellow"}}>Create Evaluation</button>)
              }






            }







            if (this.state.stage === 0) {

            var teamHtml = ""
                for (let x in this.state.results.team) {

                      //console.log(this.state.results[x])
                      todayDate = "Date: " + this.state.results.team[x].date

                      var color = "black"
                      if (this.state.results.team[x].turnover) {
                        color = "red"
                      }


                      teamHtml = <div style={{marginBottom: '10px', color: color}} id={'team' + x} onClick={() => this.nameClick(this.state.results.team[x])}><b>{this.state.results.team[x].assignment }: <u>{this.state.results.team[x].name} * medHubID: ({this.state.results.team[x].userID})</u></b></div>



                      var residentsContent = []
                      for (let y in this.state.results.team[x].members) {

                        /*
                        fetch(`https://applet-test.ucsf.edu/residencyAPIs/findid?name=` + this.state.results[x].residents[y].name, {
                          "method": "GET"
                        })
                        .then(response => response.json())
                        .then(response => {
                          console.log(response);
                          //this.setState({results: response})
                          //_forEach(response, d => console.log(d.name))
                          //console.log(this.state.results)
                          residentsContent.push(<div style={{marginLeft: '10px'}}>- {this.state.results[x].residents[y].assignment}: {this.state.results[x].residents[y].name} - {response}</div>)
                        })
                        .catch(err => {
                          console.log(err);
                        });
                      */




                        var colorRes = "black"
                        if (this.state.results.team[x].members[y].turnover) {
                          colorRes = "red"
                        }


                        residentsContent.push(<div style={{marginLeft: '10px', color: colorRes}}>- {this.state.results.team[x].members[y].name} * medHubID: ({this.state.results.team[x].members[y].userID})</div>)
                      }

                    content.push(<div>************************************************</div>)

                    content.push(teamHtml)
                    content.push(residentsContent)
                    content.push(<div>&nbsp;</div>)

                }


                /*
                for (var x in this.state.results.eval) {

                  var colorWard = "green"
                  if (this.state.results.eval[x].ward) {
                    colorWard = "blue"
                  }

                  content.push(<div style={{marginLeft: '10px', color: colorWard}}> Evalualtor: {this.state.results.eval[x].evaluator} ({this.state.results.eval[x].evaluatorID}) - Program: {this.state.results.eval[x].evaluatorProgramID} - &gt;  Evalulatee: {this.state.results.eval[x].evaluatee} ({this.state.results.eval[x].evaluateeID}) - Program: {this.state.results.eval[x].evaluateeProgramID}</div>)


                }*/

              }






            return (
                <div className="container">
                  <div className="row justify-content-center">
                    <div className="col-md-8" style={{margin: "10px"}}>
                      <h1 className="display-4 text-center">{todayDate}</h1>


{content}



                    </div>
                  </div>
                </div>
            );
          }


  };

  export default Evalulation
